mapper.select:
SELECT lm.id, lm.title, lm.material_year, lm.material_month, lm.set_number, lm.level, lm.type,
       lm.duration, lm.difficulty, lm.cover_image, lm.audio_url, lm.play_count,
       lm.mastered_rate, CASE WHEN uc.id IS NOT NULL THEN TRUE ELSE FALSE END as is_collected
FROM listening_materials lm
LEFT JOIN user_collections uc ON lm.id = uc.listening_id AND uc.user_id = #{userId}

    AND lm.material_year = #{year}
    AND lm.level = #{level}
    AND lm.type = #{type}

ORDER BY lm.material_year DESC, lm.material_month DESC, lm.set_number ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM listening_materials lm

    AND lm.material_year = #{year}
    AND lm.level = #{level}
    AND lm.type = #{type}

SELECT lm.id, lm.title, lm.material_year, lm.material_month, lm.set_number, lm.level, lm.type,
       lm.duration, lm.difficulty, lm.cover_image, lm.audio_url, lm.play_count, lm.mastered_rate, FALSE as is_collected
FROM listening_materials lm
WHERE lm.material_year = #{year}

    AND lm.material_month = #{month}

  AND lm.level = #{level}
  AND lm.set_number = #{setNumber}
ORDER BY FIELD(lm.type, 'LECTURE', 'DIALOGUE', 'PASSAGE'), lm.id ASC

SELECT lm.id, lm.title, lm.material_year, lm.material_month, lm.set_number, lm.level, lm.type,
       lm.duration, lm.difficulty, lm.cover_image, lm.audio_url, lm.play_count, lm.mastered_rate, FALSE as is_collected
FROM listening_materials lm
WHERE 1=1

    AND lm.material_year = #{year}


    AND lm.material_month = #{month}


    AND lm.level = #{level}


    AND lm.set_number = #{setNumber}


    AND lm.type = #{type}

ORDER BY lm.material_year DESC, lm.material_month DESC, FIELD(lm.type, 'LECTURE', 'DIALOGUE', 'PASSAGE'), lm.id ASC

mapper.update:
update listening_materials
set title = #{title}, material_year = #{year}, material_month = #{month}, set_number = #{setNumber}, level = #{level}, type = #{type}, duration = #{duration}, difficulty = #{difficulty}, cover_image = #{coverImage}, audio_url = #{audioUrl}, play_count = #{playCount}, mastered_rate = #{masteredRate}, created_at = #{createdAt}, updated_at = #{updatedAt}
where id = #{id}
